import SwiftUI
import SwiftData
struct OverviewCard: View { @State private var isExpanded: Bool = true; let thisWeekEvents: Int; let thisWeekHearings: Int; let thisWeekDeadlines: Int; let thisMonthEvents: Int; let activeCaseCount: Int; let nextHearingTitle: String?; let nextHearingDate: Date?; let nextHearingCourt: String?
    init(data: OverviewCardData) { self.thisWeekEvents = data.thisWeekEvents; self.thisWeekHearings = data.thisWeekHearings; self.thisWeekDeadlines = data.thisWeekDeadlines; self.thisMonthEvents = data.thisMonthEvents; self.activeCaseCount = data.activeCaseCount; self.nextHearingTitle = data.nextHearingTitle; self.nextHearingDate = data.nextHearingDate; self.nextHearingCourt = data.nextHearingCourt }
    var body: some View { VStack(spacing: 0) { collapseHeader; if isExpanded { overviewGrid.padding(.horizontal, Spacing.base).padding(.bottom, Spacing.md) } }.background(Color.surfaceCard).clipShape(RoundedRectangle(cornerRadius: CornerRadius.card)).shadow(color: .black.opacity(0.05), radius: 6, x: 0, y: 1).padding(.horizontal, Spacing.base).padding(.top, Spacing.sm) }
    private var collapseHeader: some View { Button { withAnimation(.easeInOut(duration: 0.3)) { isExpanded.toggle() } } label: { HStack(spacing: Spacing.sm) { HStack(spacing: Spacing.xs) { Image(systemName: "rectangle.3.group.fill").font(.system(size: 14, weight: .medium)).foregroundColor(.tealLink); Text("本周概览").font(.cnSubhead).foregroundColor(.textPrimary); Text("\(thisWeekEvents) 次互动").font(.cnCaption2).foregroundColor(.tealLink).padding(.horizontal, Spacing.sm).padding(.vertical, 2).background(Color.tealLink.opacity(0.1)).clipShape(RoundedRectangle(cornerRadius: CornerRadius.tag)) }; Spacer(); Image(systemName: "chevron.down").font(.system(size: 13, weight: .medium)).foregroundColor(.textTertiary).rotationEffect(.degrees(isExpanded ? 0 : -90)) }.padding(.horizontal, Spacing.base).padding(.vertical, Spacing.md) }.buttonStyle(.plain) }
    private var overviewGrid: some View { VStack(spacing: Spacing.md) { statBubblesRow; monthlyWorkloadBar; if let title = nextHearingTitle { nextHearingRow(title: title, date: nextHearingDate, court: nextHearingCourt) } } }
    private var statBubblesRow: some View { HStack(spacing: Spacing.md) { StatBubble(icon: "calendar", count: thisWeekEvents, label: "本周互动", color: .tealLink); StatBubble(icon: "hammer.fill", count: thisWeekHearings, label: "开庭", color: .coralWarm); StatBubble(icon: "clock.badge.exclamationmark", count: thisWeekDeadlines, label: "截止", color: .statusWarning) } }
    private var monthlyWorkloadBar: some View { VStack(alignment: .leading, spacing: Spacing.sm) { HStack { Text("本月工作量").font(.cnCaption1).foregroundColor(.textSecondary); Spacer(); Text("\(thisMonthEvents) 件事项").font(.cnCaption2).foregroundColor(.textTertiary) }; GeometryReader { geo in ZStack(alignment: .leading) { RoundedRectangle(cornerRadius: 4).fill(Color.divider).frame(height: 8); let maxEvents: CGFloat = 30; let progress = min(CGFloat(thisMonthEvents) / maxEvents, 1.0); let barWidth = geo.size.width * progress; RoundedRectangle(cornerRadius: 4).fill(LinearGradient(colors: [.tealLink, .tealLink.opacity(0.6)], startPoint: .leading, endPoint: .trailing)).frame(width: max(barWidth, 8), height: 8) } }.frame(height: 8) } }
    private func nextHearingRow(title: String, date: Date?, court: String?) -> some View { HStack(spacing: Spacing.md) { ZStack { RoundedRectangle(cornerRadius: CornerRadius.nestedCard).fill(Color.coralWarm.opacity(0.1)).frame(width: 44, height: 44); Image(systemName: "hammer.fill").font(.system(size: 20, weight: .medium)).foregroundColor(.coralWarm) }; VStack(alignment: .leading, spacing: 2) { HStack(spacing: Spacing.xs) { Image(systemName: "bell.fill").font(.system(size: 9)).foregroundColor(.coralWarm); Text("下个开庭").font(.cnCaption2).foregroundColor(.coralWarm) }; Text(title).font(.cnSubhead).foregroundColor(.textPrimary).lineLimit(1); HStack(spacing: Spacing.sm) { if let date = date { HStack(spacing: 3) { Image(systemName: "calendar").font(.system(size: 10)); Text(date.formatted(.dateTime.month(.abbreviated).day().hour().minute())) }.font(.cnCaption2).foregroundColor(.textSecondary) }; if let court = court { Text("·").foregroundColor(.textTertiary); Text(court).font(.cnCaption2).foregroundColor(.textSecondary).lineLimit(1) } } }; Spacer() }.padding(Spacing.sm).background(Color.coralWarm.opacity(0.04)).clipShape(RoundedRectangle(cornerRadius: CornerRadius.nestedCard)) }
}
private struct StatBubble: View { let icon: String; let count: Int; let label: String; let color: Color
    var body: some View { VStack(spacing: Spacing.xs) { ZStack { Circle().stroke(color.opacity(0.15), lineWidth: 3).frame(width: 60, height: 60); VStack(spacing: 2) { Image(systemName: icon).font(.system(size: 13, weight: .medium)).foregroundColor(color); Text("\(count)").font(.system(size: 20, weight: .bold, design: .rounded)).foregroundColor(color) } }; Text(label).font(.cnCaption2).foregroundColor(.textSecondary) }.frame(maxWidth: .infinity) }
}
@MainActor struct OverviewCardData { let thisWeekEvents: Int; let thisWeekHearings: Int; let thisWeekDeadlines: Int; let thisMonthEvents: Int; let activeCaseCount: Int; let nextHearingTitle: String?; let nextHearingDate: Date?; let nextHearingCourt: String?
    init(modelContext: ModelContext) { let calendar = Calendar.current; let now = Date(); let weekday = calendar.component(.weekday, from: now); let daysToMonday = (weekday + 5) % 7; let monday = calendar.startOfDay(for: calendar.date(byAdding: .day, value: -daysToMonday, to: now)!); let nextMonday = calendar.date(byAdding: .day, value: 7, to: monday)!; let startOfMonth = calendar.date(from: calendar.dateComponents([.year, .month], from: now))!; let startOfNextMonth = calendar.date(byAdding: .month, value: 1, to: startOfMonth)!; let weekEventDescriptor = FetchDescriptor<event>(predicate: #Predicate { event in event.date != nil && event.date! >= monday && event.date! < nextMonday }); thisWeekEvents = (try? modelContext.fetchCount(weekEventDescriptor)) ?? 0; let hearingDescriptor = FetchDescriptor<event>(predicate: #Predicate { event in event.date != nil && event.date! >= monday && event.date! < nextMonday && (event.eventTypeRaw == "hearing") }); thisWeekHearings = (try? modelContext.fetchCount(hearingDescriptor)) ?? 0; let deadlineDescriptor = FetchDescriptor<event>(predicate: #Predicate { event in event.date != nil && event.date! >= monday && event.date! < nextMonday && (event.eventTypeRaw == "deadline") }); thisWeekDeadlines = (try? modelContext.fetchCount(deadlineDescriptor)) ?? 0; let monthDescriptor = FetchDescriptor<event>(predicate: #Predicate { event in event.date != nil && event.date! >= startOfMonth && event.date! < startOfNextMonth }); thisMonthEvents = (try? modelContext.fetchCount(monthDescriptor)) ?? 0; let activeCaseDescriptor = FetchDescriptor<case>(predicate: #Predicate { c in !c.isArchived && (c.caseStatusRaw == "consulting" || c.caseStatusRaw == "retained" || c.caseStatusRaw == "filing" || c.caseStatusRaw == "inTrial" || c.caseStatusRaw == "enforcing" || c.caseStatusRaw == "appealed") }); activeCaseCount = (try? modelContext.fetchCount(activeCaseDescriptor)) ?? 0; let nextHearingEventDescriptor = FetchDescriptor<event>(predicate: #Predicate { event in (event.statusRaw == "planned" || event.statusRaw == "confirmed") && (event.date != nil) && (event.date! >= now) && (event.eventTypeRaw == "hearing") }, sortBy: [SortDescriptor(\.date, order: .forward)]); let upcomingHearings = (try? modelContext.fetch(nextHearingEventDescriptor)) ?? []; let nextCaseEventDescriptor = FetchDescriptor<caseevent>(predicate: #Predicate { ce in !ce.isCompleted && ce.date >= now && (ce.eventTypeRaw == "trial" || ce.eventTypeRaw == "sentencing") }, sortBy: [SortDescriptor(\.date, order: .forward)]); let upcomingCaseEvents = (try? modelContext.fetch(nextCaseEventDescriptor)) ?? []; let eventHearing: (title: String, date: Date, court: String?)? = { if let e = upcomingHearings.first, let d = e.date { return (e.title, d, nil) }; return nil }(); let caseHearing: (title: String, date: Date, court: String?)? = { if let ce = upcomingCaseEvents.first { return (ce.title, ce.date, ce.case?.court) }; return nil }(); if let eh = eventHearing, let ch = caseHearing { if eh.date < ch.date { nextHearingTitle = eh.title; nextHearingDate = eh.date; nextHearingCourt = nil } else { nextHearingTitle = ch.title; nextHearingDate = ch.date; nextHearingCourt = ch.court } } else if let eh = eventHearing { nextHearingTitle = eh.title; nextHearingDate = eh.date; nextHearingCourt = nil } else if let ch = caseHearing { nextHearingTitle = ch.title; nextHearingDate = ch.date; nextHearingCourt = ch.court } else { nextHearingTitle = nil; nextHearingDate = nil; nextHearingCourt = nil } }
}